### 📅 SEMANA 3-4: Validação robusta e volume de prática

**Objetivo**: Debugging 80 → 85+, implementar 3 hooks customizados

#### Dia 15-17: Adicionar validação HTTP em useTasks

**Exercício prático**:
```javascript
/**
 * @typedef {Object} HTTPError
 * @property {number} status - Código HTTP
 * @property {string} statusText - Mensagem HTTP
 * @property {string} message - Mensagem customizada
 */

/**
 * Valida resposta HTTP e lança erro se necessário
 * @param {Response} response
 * @throws {HTTPError}
 * @returns {Promise<Response>}
 */
async function validateResponse(response) {
  if (!response.ok) {
    const error = new Error(`HTTP ${response.status}: ${response.statusText}`);
    error.status = response.status;
    error.statusText = response.statusText;
    throw error;
  }
  return response;
}

function useTasks() {
  useEffect(() => {
    let active = true;

    async function fetchTasks() {
      try {
        setLoading(true);
        const response = await fetch('/api/tasks');
        await validateResponse(response); // NOVO
        const data = await response.json();

        if (active) {
          setTasks(data);
          setError(null);
        }
      } catch (error) {
        if (!active) return;

        // Diferenciar tipos de erro
        if (error.name === 'TypeError') {
          setError('Erro de conexão. Verifique sua internet.');
        } else if (error.status) {
          setError(`Erro ${error.status}: ${error.statusText}`);
        } else {
          setError('Erro desconhecido ao carregar tarefas.');
        }
      } finally {
        if (active) setLoading(false);
      }
    }

    fetchTasks();
    return () => { active = false; };
  }, []);
}
```

**Validação**:
- Testar com API que retorna 404: verificar mensagem "Erro 404: Not Found"
- Testar desconectando internet: verificar mensagem "Erro de conexão"
- ESLint sem warnings

