#### Dia 18-20: Implementar useUsers com padrões consolidados

**Exercício prático**:
```javascript
/**
 * @typedef {Object} User
 * @property {string} id
 * @property {string} name
 * @property {string} email
 */

/**
 * Hook customizado para gerenciar lista de usuários
 * @returns {{
 *   users: User[],
 *   loading: boolean,
 *   error: string|null,
 *   deleteUser: (userId: string) => Promise<void>
 * }}
 */
function useUsers() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    let active = true;

    async function fetchUsers() {
      try {
        setLoading(true);
        const response = await fetch('/api/users');
        await validateResponse(response);
        const data = await response.json();

        if (active) {
          setUsers(data);
          setError(null);
        }
      } catch (error) {
        if (!active) return;
        setError(classifyError(error)); // Reutilizar lógica
      } finally {
        if (active) setLoading(false);
      }
    }

    fetchUsers();
    return () => { active = false; };
  }, []);

  /**
   * Remove usuário com atualização otimista
   * @param {string} userId
   * @returns {Promise<void>}
   */
  const deleteUser = async (userId) => {
    const previousUsers = users;

    // Atualização otimista
    setUsers((current) => current.filter(u => u.id !== userId));

    try {
      const response = await fetch(`/api/users/${userId}`, {
        method: 'DELETE'
      });
      await validateResponse(response);
    } catch (error) {
      // Rollback em caso de erro
      setUsers(previousUsers);
      setError(classifyError(error));
    }
  };

  return { users, loading, error, deleteUser };
}
```

**Validação**:
- Implementação leva ≤70% do tempo de useTasks
- Padrões aplicados: cleanup, validação HTTP, diferenciação de erros, JSDoc completo
- ESLint sem warnings

